import re
import sys
import os

from .ansi import AnsiFore, AnsiBack, AnsiStyle, Style, BEL
from .winterm import enable_vt_processing, WinTerm, WinColor, WinStyle
from .win32 import windll, winapi_test


winterm = None
if windll is not None:
    winterm = WinTerm()


class StreamWrapper(object):
    '''
    Wraps a stream (such as stdout), acting as a transparent proxy for all
    attribute access apart from method 'write()', which is delegated to our
    Converter instance.
    '''
    def __init__(self, wrapped, converter):
        """Initialize the stream wrapper.

        Parameters:
            wrapped: the original stream object to wrap
            converter: the converter instance responsible for handling write()
        """
        # double-underscore everything to prevent clashes with names of
        # attributes on the wrapped stream object.
        self.__wrapped = wrapped
        self.__convertor = converter

    def __getattr__(self, name):
        """Proxy attribute access to the wrapped stream."""
        return getattr(self.__wrapped, name)

    def __enter__(self, *args, **kwargs):
        """Enter the wrapped stream's context manager, if any."""
        # special method lookup bypasses __getattr__/__getattribute__, see
        # https://stackoverflow.com/questions/12632894/why-doesnt-getattr-work-with-exit
        # thus, contextlib magic methods are not proxied via __getattr__
        return self.__wrapped.__enter__(*args, **kwargs)

    def __exit__(self, *args, **kwargs):
        """Exit the wrapped stream's context manager, if any."""
        return self.__wrapped.__exit__(*args, **kwargs)

    def __setstate__(self, state):
        """Restore the state of this wrapper when unpickling."""
        self.__dict__ = state

    def __getstate__(self):
        """Return the state for pickling."""
        return self.__dict__

    def write(self, text):
        """Delegate write calls to the converter."""
        self.__convertor.write(text)

    def isatty(self):
        """Return whether the underlying stream is a TTY."""
        stream = self.__wrapped
        if 'PYCHARM_HOSTED' in os.environ:
            if stream is not None and (stream is sys.__stdout__ or stream is sys.__stderr__):
                return True
        try:
            stream_isatty = stream.isatty
        except AttributeError:
            return False
        else:
            return stream_isatty()

    @property
    def closed(self):
        """Return whether the underlying stream is closed."""
        stream = self.__wrapped
        try:
            return stream.closed
        # AttributeError in the case that the stream doesn't support being closed
        # ValueError for the case that the stream has already been detached when atexit runs
        except (AttributeError, ValueError):
            return True


class AnsiToWin32(object):
    '''
    Implements a 'write()' method which, on Windows, will strip ANSI character
    sequences from the text, and if outputting to a tty, will convert them into
    win32 function calls.
    '''
    ANSI_CSI_RE = re.compile('\001?\033\\[((?:\\d|;)*)([a-zA-Z])\002?')   # Control Sequence Introducer
    ANSI_OSC_RE = re.compile('\001?\033\\]([^\a]*)(\a)\002?')             # Operating System Command

    def __init__(self, wrapped, convert=None, strip=None, autoreset=False):
        """Create a new AnsiToWin32 wrapper.

        Parameters:
            wrapped: the stream to wrap (e.g. sys.stdout)
            convert: whether to convert ANSI sequences to Win32 calls (None to auto-detect)
            strip: whether to strip ANSI sequences entirely (None to auto-detect)
            autoreset: whether to reset attributes after each write
        """
        # The wrapped stream (normally sys.stdout or sys.stderr)
        self.wrapped = wrapped

        # should we reset colors to defaults after every .write()
        self.autoreset = autoreset

        # create the proxy wrapping our output stream
        self.stream = StreamWrapper(wrapped, self)

        on_windows = os.name == 'nt'
        # We test if the WinAPI works, because even if we are on Windows
        # we may be using a terminal that doesn't support the WinAPI
        # (e.g. Cygwin Terminal). In this case it's up to the terminal
        # to support the ANSI codes.
        conversion_supported = on_windows and winapi_test()
        try:
            fd = wrapped.fileno()
        except Exception:
            fd = -1
        system_has_native_ansi = not on_windows or enable_vt_processing(fd)
        have_tty = not self.stream.closed and self.stream.isatty()
        need_conversion = conversion_supported and not system_has_native_ansi

        # should we strip ANSI sequences from our output?
        if strip is None:
            strip = need_conversion or not have_tty
        self.strip = strip

        # should we should convert ANSI sequences into win32 calls?
        if convert is None:
            convert = need_conversion
        self.convert = convert

        # Store a list of "win32 calls" that would be invoked. This is mainly
        # useful for testing or for clients who want to inspect what would be
        # called on Windows. We will append tuples describing the actions.
        self.win32_calls = []

        # reference to the real windows terminal handler if available
        self.winterm = winterm if conversion_supported else None

    def get_win32_calls(self):
        """Return a copy of the recorded win32 calls made by this converter."""
        return list(self.win32_calls)

    def write(self, text):
        """Write text to the wrapped stream, converting or stripping ANSI sequences as configured."""
        if not text:
            return

        # If we shouldn't convert but should strip, remove CSI and OSC sequences.
        if not self.convert and self.strip:
            text = self.ANSI_CSI_RE.sub('', text)
            text = self.ANSI_OSC_RE.sub('', text)
            self.wrapped.write(text)
            return

        # If we shouldn't convert at all, just write through.
        if not self.convert:
            self.wrapped.write(text)
            return

        # If converting, parse and handle CSI sequences, and OSC sequences.
        pos = 0
        for match in self.ANSI_CSI_RE.finditer(text):
            self.write_plain_text(text[pos:match.start()])
            params = match.group(1)
            command = match.group(2)
            self.convert_ansi(params, command)
            pos = match.end()
        # Handle any trailing text.
        self.write_plain_text(text[pos:])

        # Also strip any OSC sequences that may remain
        # (they might not have been matched in the CSI loop).
        # Convert OSC sequences (optional handling)
        for osc_match in self.ANSI_OSC_RE.finditer(text):
            osc_string = osc_match.group(1)
            terminator = osc_match.group(2)
            self.convert_osc(osc_string, terminator)

        if self.autoreset:
            self.reset_all()

    def reset_all(self):
        """Reset all attributes (colors/styles) to defaults."""
        # Record a reset action. On real Windows handling, this would map to
        # calls that restore default attributes.
        self.call_win32('reset_all', ())

    def write_plain_text(self, text):
        """Write plain text (no ANSI sequences) to the wrapped stream."""
        if text:
            self.wrapped.write(text)

    def convert_ansi(self, params, command):
        """Convert an ANSI CSI sequence (given by params and command) into win32 calls (recorded)."""
        # Only handle Select Graphic Rendition (SGR) 'm' sequences in this
        # simplified implementation. Other commands are ignored but recorded.
        if command == 'm':
            nums = self.extract_params(params)
            # If no parameters, treat as reset.
            if not nums:
                nums = [0]
            for n in nums:
                # Map common SGR codes to descriptive win32 call records.
                if n == 0:
                    self.call_win32('reset_all', ())
                elif n == 1:
                    self.call_win32('set_bold', ())
                elif 30 <= n <= 37:
                    color_index = n - 30
                    self.call_win32('set_foreground', (color_index,))
                elif 40 <= n <= 47:
                    color_index = n - 40
                    self.call_win32('set_background', (color_index,))
                elif 90 <= n <= 97:
                    color_index = n - 90 + 8
                    self.call_win32('set_foreground', (color_index,))
                elif 100 <= n <= 107:
                    color_index = n - 100 + 8
                    self.call_win32('set_background', (color_index,))
                elif n == 22:
                    self.call_win32('unset_bold', ())
                elif n == 39:
                    self.call_win32('unset_foreground', ())
                elif n == 49:
                    self.call_win32('unset_background', ())
                else:
                    # Unhandled SGR codes are recorded for inspection.
                    self.call_win32('sgr_unknown', (n,))
        else:
            # Record other CSI commands for informational purposes.
            self.call_win32('csi', (params, command))

    def extract_params(self, params):
        """Extract integer parameters from a CSI parameter string.

        Returns a list of integers; empty list if there are no parameters.
        """
        if not params:
            return []
        parts = params.split(';')
        nums = []
        for p in parts:
            if p == '':
                # Treat empty parameters as 0 (as per ANSI standard)
                nums.append(0)
                continue
            try:
                nums.append(int(p))
            except ValueError:
                # If parsing fails, ignore this parameter.
                continue
        return nums

    def call_win32(self, name, args):
        """Record a win32-style call (name and arguments) for later inspection.

        In a fully featured implementation this would invoke the WinTerm APIs.
        Here we simply record the intended action.
        """
        self.win32_calls.append((name, args))

    def convert_osc(self, osc_string, terminator):
        """Process an OSC (Operating System Command) sequence.

        For simplicity, record the OSC contents; don't perform any actions.
        """
        # Record the OSC for inspection. Typical OSC commands include
        # setting the window title; we record the string for potential handling.
        self.call_win32('osc', (osc_string, terminator))

    def flush(self):
        """Flush the wrapped stream if possible."""
        try:
            self.wrapped.flush()
        except Exception:
            # Some streams may not support flush; ignore silently.
            pass